-- Sample data (useful for demo/testing)
-- Password hashes are BCrypt; easiest is to register via API, but these are here for quick DB seeding.
-- NOTE: Replace password_hash with one generated by your backend if you want to log in with these users.

USE smart_focus;

ON DUPLICATE KEY UPDATE username = username;

-- Find demo user id
SET @demo_id = (SELECT id FROM users WHERE username='demo' LIMIT 1);



